Here is the commit message:
Fix DHE Null CKE vulnerability

If client auth is used then a server can seg fault in the event of a DHE
cipher being used and a zero length ClientKeyExchange message being sent
by the client. This could be exploited in a DoS attack.

CVE-2015-1787

Reviewed-by: Richard Levitte <levitte@openssl.org>

Here is the root cause:
The bug is caused by the server's failure to properly validate the length of the `ClientKeyExchange` message when using DHE ciphers. If a zero-length message is sent by the client, the server attempts to process it without adequate checks, leading to a segmentation fault. This vulnerability can be exploited to perform a Denial of Service (DoS) attack.

Here is the patch:

 int ssl3_get_client_key_exchange(SSL *s)
 {
     int i, al, ok;
     long n;
     unsigned long alg_k;
     unsigned char *p;
 #ifndef OPENSSL_NO_RSA
     RSA *rsa = NULL;
     EVP_PKEY *pkey = NULL;
 #endif
 #ifndef OPENSSL_NO_DH
     BIGNUM *pub = NULL;
     DH *dh_srvr, *dh_clnt = NULL;
 #endif
 #ifndef OPENSSL_NO_KRB5
     KSSL_ERR kssl_err;
 #endif                          /* OPENSSL_NO_KRB5 */

 #ifndef OPENSSL_NO_ECDH
     EC_KEY *srvr_ecdh = NULL;
     EVP_PKEY *clnt_pub_pkey = NULL;
     EC_POINT *clnt_ecpoint = NULL;
     BN_CTX *bn_ctx = NULL;
 #endif

     n = s->method->ssl_get_message(s,
                                    SSL3_ST_SR_KEY_EXCH_A,
                                    SSL3_ST_SR_KEY_EXCH_B,
                                    SSL3_MT_CLIENT_KEY_EXCHANGE, 2048, &ok);

     if (!ok)
         return ((int)n);
     p = (unsigned char *)s->init_msg;

     alg_k = s->s3->tmp.new_cipher->algorithm_mkey;

 #ifndef OPENSSL_NO_RSA
     if (alg_k & SSL_kRSA) {
         unsigned char rand_premaster_secret[SSL_MAX_MASTER_KEY_LENGTH];
         int decrypt_len;
         unsigned char decrypt_good, version_good;
         size_t j;

         /* FIX THIS UP EAY EAY EAY EAY */
         if (s->s3->tmp.use_rsa_tmp) {
             if ((s->cert != NULL) && (s->cert->rsa_tmp != NULL))
                 rsa = s->cert->rsa_tmp;
             /*
              * Don't do a callback because rsa_tmp should be sent already
              */
             if (rsa == NULL) {
                 al = SSL_AD_HANDSHAKE_FAILURE;
                 SSLerr(SSL_F_SSL3_GET_CLIENT_KEY_EXCHANGE,
                        SSL_R_MISSING_TMP_RSA_PKEY);
                 goto f_err;

             }
         } else {
             pkey = s->cert->pkeys[SSL_PKEY_RSA_ENC].privatekey;
             if ((pkey == NULL) ||
                 (pkey->type != EVP_PKEY_RSA) || (pkey->pkey.rsa == NULL)) {
                 al = SSL_AD_HANDSHAKE_FAILURE;
                 SSLerr(SSL_F_SSL3_GET_CLIENT_KEY_EXCHANGE,
                        SSL_R_MISSING_RSA_CERTIFICATE);
                 goto f_err;
             }
             rsa = pkey->pkey.rsa;
         }

         /* TLS and [incidentally] DTLS{0xFEFF} */
         if (s->version > SSL3_VERSION && s->version != DTLS1_BAD_VER) {
             n2s(p, i);
             if (n != i + 2) {
                 if (!(s->options & SSL_OP_TLS_D5_BUG)) {
                     al = SSL_AD_DECODE_ERROR;
                     SSLerr(SSL_F_SSL3_GET_CLIENT_KEY_EXCHANGE,
                            SSL_R_TLS_RSA_ENCRYPTED_VALUE_LENGTH_IS_WRONG);
                     goto f_err;
                 } else
                     p -= 2;
             } else
                 n = i;
         }

         /*
          * Reject overly short RSA ciphertext because we want to be sure
          * that the buffer size makes it safe to iterate over the entire
          * size of a premaster secret (SSL_MAX_MASTER_KEY_LENGTH). The
          * actual expected size is larger due to RSA padding, but the
          * bound is sufficient to be safe.
          */
         if (n < SSL_MAX_MASTER_KEY_LENGTH) {
             al = SSL_AD_DECRYPT_ERROR;
             SSLerr(SSL_F_SSL3_GET_CLIENT_KEY_EXCHANGE,
                    SSL_R_TLS_RSA_ENCRYPTED_VALUE_LENGTH_IS_WRONG);
             goto f_err;
         }

         /*
          * We must not leak whether a decryption failure occurs because of
          * Bleichenbacher's attack on PKCS #1 v1.5 RSA padding (see RFC 2246,
          * section 7.4.7.1). The code follows that advice of the TLS RFC and
          * generates a random premaster secret for the case that the decrypt
          * fails. See https://tools.ietf.org/html/rfc5246#section-7.4.7.1
          */

